// Vendored Howler.js entry: sourced from the npm `howler` package (pinned in
// package.json) and re-emitted by esbuild as a standalone classic script at the
// served path the audio surfaces reference (/static/js/vendor/howler.min.js). It
// exposes the Howl + Howler globals on window, matching the upstream UMD build's
// globals (#1088). Used by the per-question audio controller for iOS-friendly
// playback (Web Audio under the hood auto-unlocks the AudioContext on the first
// user gesture, then plays freely without a fresh gesture per clip).
import { Howl, Howler } from 'howler';

window.Howl = Howl;
window.Howler = Howler;
